-- ============================================================
-- 1. CREATE PLAYERS TABLE
-- ============================================================
CREATE TABLE IF NOT EXISTS players (
  id         UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  first_name TEXT NOT NULL,
  last_name  TEXT NOT NULL,
  email      TEXT UNIQUE,
  centre     TEXT,
  department TEXT,
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_players_email ON players(email);

-- ============================================================
-- 2. ADD PLAYER FK COLUMNS TO COUPLES (if not already added)
-- ============================================================
ALTER TABLE couples
  ADD COLUMN IF NOT EXISTS player_1_id UUID REFERENCES players(id),
  ADD COLUMN IF NOT EXISTS player_2_id UUID REFERENCES players(id);

-- ============================================================
-- 3. SEED PLAYERS
-- ============================================================

-- ============================================================
-- 4. CLEAR OLD DUMMY DATA, INSERT REAL COUPLES
-- ============================================================
DELETE FROM group_standings;
DELETE FROM match_log;
DELETE FROM matches;
DELETE FROM users;
DELETE FROM couples;


-- ============================================================
-- 5. REPLACE AUTH TRIGGER WITH EMAIL-BASED COUPLE LOOKUP
-- ============================================================
DROP TRIGGER IF EXISTS tr_link_test_user ON public.users;
DROP FUNCTION IF EXISTS fn_link_test_user();
DROP TRIGGER IF EXISTS tr_link_user_to_couple ON public.users;
DROP FUNCTION IF EXISTS fn_link_user_to_couple();

CREATE OR REPLACE FUNCTION fn_link_user_to_couple()
RETURNS TRIGGER LANGUAGE plpgsql SECURITY DEFINER AS $$
DECLARE
  v_player_id UUID;
  v_couple_id  UUID;
BEGIN
  SELECT id INTO v_player_id FROM players WHERE email = NEW.email;
  IF v_player_id IS NOT NULL THEN
    SELECT id INTO v_couple_id FROM couples
      WHERE player_1_id = v_player_id OR player_2_id = v_player_id
      LIMIT 1;
    IF v_couple_id IS NOT NULL THEN
      NEW.couple_id := v_couple_id;
    END IF;
  END IF;
  RETURN NEW;
END;
$$;

CREATE TRIGGER tr_link_user_to_couple
  BEFORE INSERT OR UPDATE OF email ON public.users
  FOR EACH ROW EXECUTE FUNCTION fn_link_user_to_couple();

-- Re-trigger for any existing users
UPDATE public.users SET email = email WHERE email IS NOT NULL;
